def validate_xml_file(file_path: str) -> Tuple[bool, Optional[ET.Element], str]:
    """
    Reads an XML file from disk and validates it safely.
    
    Args:
        file_path: Path to the XML file.
        
    Returns:
        A tuple of (is_valid, root_element, message).
    """
    try:
        with open(file_path, "rb") as f:
            xml_content = f.read()
        return validate_and_parse_xml(xml_content)
    except FileNotFoundError:
        return False, None, f"File not found: {file_path}"
    except PermissionError:
        return False, None, f"Permission denied reading file: {file_path}"
    except IOError as e:
        return False, None, f"I/O error reading file: {e}"


def get_xml_summary(root: ET.Element) -> dict:
    """
    Returns a summary of a parsed XML document's structure.
    
    Args:
        root: The root Element from a successfully parsed XML document.
        
    Returns:
        A dictionary with structural information about the XML.
    """
    if root is None:
        return {"error": "No root element provided."}

    tag_counts = {}
    max_depth = 0

    def _traverse(element, depth):
        nonlocal max_depth
        if depth > max_depth:
            max_depth = depth
        tag = element.tag
        tag_counts[tag] = tag_counts.get(tag, 0) + 1
        for child in element:
            _traverse(child, depth + 1)

    _traverse(root, 0)

    return {
        "root_tag": root.tag,
        "root_attributes": dict(root.attrib),
        "total_unique_tags": len(tag_counts),
        "total_elements": sum(tag_counts.values()),
        "max_depth": max_depth,
        "tag_counts": tag_counts,
    }


